module top_module(x,y,CLR,C,Q);input x,y;
wire g;
input CLR, C;
reg tmp;
output Q;


assign g = x*y;


  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C or posedge CLR or posedge dbg_halt)
    begin 
      if (CLR) 
        tmp <= 4'b0000; 
      else 
        tmp <= tmp + g; 
    end 

assign Q = tmp; 

endmodule
